# Compliance check function
def compliance_check(article):
    issues = []
    content = article["content"]
    title = article["title"]
    excerpt = article["excerpt"]
    full_text = content + " " + title + " " + excerpt

    # Check for tickers
    tickers = ["THLV", "THIR", "SPLV", "SPY", "SPHD", "FDLO", "USMV", "XLU", "XLP", "VOO"]
    for t in tickers:
        # Look for standalone ticker (word boundary)
        if re.search(r'\b' + t + r'\b', full_text):
            issues.append(f"TICKER found: {t}")

    # Check for em dashes
    if "\u2014" in full_text:
        issues.append("Em dash found")

    # Check for banned phrases
    banned = [
        "thorfunds.com",
        "tactical",
        "Downside Protection",
        "downside protection",
        "reduces drawdowns",
        "that's a feature, not a bug",
    ]
    for b in banned:
        if b.lower() in full_text.lower():
            issues.append(f"Banned phrase: {b}")

    # Check for performance numbers (NAV, AUM, expense ratios)
    if re.search(r'expense ratio', full_text, re.IGNORECASE):
        issues.append("Expense ratio mention")
    if re.search(r'\bNAV\b', full_text):
        issues.append("NAV mention")
    if re.search(r'\bAUM\b', full_text):
        issues.append("AUM mention")

    return issues

# Run compliance checks
print("=== COMPLIANCE CHECK ===")
all_clean = True
for a in new_articles:
    issues = compliance_check(a)
    if issues:
        all_clean = False
        print(f"\n❌ {a['slug']}:")
        for i in issues:
            print(f"   - {i}")
    else:
        print(f"✅ {a['slug']}: CLEAN")

if not all_clean:
    print("\n⚠️  Fix issues before proceeding!")
    import sys
    sys.exit(1)

